func (q *Queries) ListScheduleSummaries(ctx context.Context, arg ListScheduleSummariesParams) ([]ListScheduleSummariesRow, error) {
	rows, err := q.db.Query(ctx, listScheduleSummaries,
		arg.OrgID,
		arg.ProjectID,
		arg.EnvironmentID,
		arg.RowLimit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListScheduleSummariesRow
	for rows.Next() {
		var i ListScheduleSummariesRow
		if err := rows.Scan(
			&i.ScheduleID,
			&i.InstanceID,
			&i.OrgID,
			&i.ProjectID,
			&i.EnvironmentID,
			&i.Type,
			&i.TaskID,
			&i.DedupKey,
			&i.ExternalID,
			&i.CronExpression,
			&i.Timezone,
			&i.Payload,
			&i.SecretBindings,
			&i.Workspace,
			&i.RunOptions,
			&i.ScheduleActive,
			&i.InstanceActive,
			&i.Generation,
			&i.NextScheduledAt,
			&i.NextDueAt,
			&i.LastScheduledAt,
			&i.CatchUpPolicy,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

